no-links.general:
.no-links {
.markdown-source-view.mod-cm6 .cm-hmd-internal-link,
  .markdown-rendered .internal-link {
    background-color: transparent;
    padding: 0px;

    &:hover {
      color: var(--link-color-hover);
      transition: color 0.3s ease-out;
      background-color: transparent;
}};
}

box-links.general:
.box-links {
.markdown-source-view.mod-cm6 .cm-hmd-internal-link,
  .markdown-rendered .internal-link {
    border: 1px solid var(--highlight-med);
    background-color: transparent;
    
    &:hover {
      background-color: var(--highlight-med);
      color: var(--link-color);
    }
};
}

kanban-modern.general:
.kanban-modern {
.kanban-plugin__lane {
    background-color: var(--background-primary) !important;
  };
.kanban-plugin__lane:hover {
    outline: 1px solid var(--highlight-med);
  };
.kanban-plugin__item-title-wrapper {
    background-color: var(--overlay);
    border-radius: 10px;
    border: 1px solid var(--highlight-high);
    padding: 10px;
    transition-duration: .3s;
    transition-property: border-color, box-shadow, background-color;
  };
.kanban-plugin__item, .kanban-plugin__item-button-wrapper, .kanban-plugin__item-form /*fix*/ {
    outline: none;
    border: none;
  };
.kanban-plugin__item-title-wrapper:hover {
    border: 1px solid var(--text-faint);
    cursor: pointer;
  };
button.kanban-plugin__new-item-button {
    background-color: transparent;
    color: var(--text-faint);
  };
button.kanban-plugin__new-item-button:hover {
    background-color: transparent;
    color: var(--color-pink);
};
}

tokei-plugin.general:
.tokei-plugin {
.time {
    padding: 20px;
    font-size: 3.2em;
    text-shadow: none;
    color: var(--pine);
  };
.date {
    font-size: 1.5em;
    color: var(--rose);
  };
.timezone-container {
    padding: 15px;
    gap: 15px;
  };
.timezone-pair {
    flex-direction: row;
    border: 2px dotted var(--highlight-high);
    background-color: transparent;
    border-radius: 5px;
  };
.timezone-name {
    color: var(--subtle);
    writing-mode: vertical-rl;
    transform: rotate(180deg);
  };
.timezone-time {
    color: var(--text-normal);
};
}

seamless-dataview.general:
th) {
border: 1px solid var(--table-border-color);
font-size: var(--font-text-size);
}

callout-math.general:
.callout-math .callout {
border-width: 2px;
border-color: rgba(var(--callout-color));
border-radius: 0px;
background-color: transparent;
}

no-center.general:
.no-center {
:is(:is(.markdown-source-view.mod-cm6) :is(.cm-content, .cm-line), .markdown-rendered) :is(img, .external-embed, .internal-embed audio, .internal-embed video, .iframe-external-embed) {
  margin-inline: 0;
  display: inline;
  border-radius: 10px;
};
table, .table-wrapper {
  margin-inline: 0;
};
}
